import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const Dashboard = ({ schedule, setSchedule }) => {
  const navigate = useNavigate();
  
  // Local state for the form inputs
  const [syllabus, setSyllabus] = useState('');
  const [targetDate, setTargetDate] = useState('');
  const [loading, setLoading] = useState(false);

  // Function to generate the daily tasks
  const generateSchedule = () => {
    if (!syllabus || !targetDate) {
      alert("Please enter both the syllabus and a target date!");
      return;
    }

    setLoading(true);
    
    // Simulate AI logic: splitting the syllabus by commas into days
    setTimeout(() => {
      const topics = syllabus.split(',').map(item => item.trim());
      const generatedDays = topics.map((topic, index) => ({
        day: index + 1,
        topic: topic || `Topic ${index + 1}`,
        status: 'pending',
        // Calculate date for each day starting from today
        date: new Date(Date.now() + index * 86400000).toLocaleDateString()
      }));

      setSchedule(generatedDays); // Updates App.js state
      setLoading(false);
    }, 1000);
  };

  const handleResetPlan = () => {
    if (window.confirm("Clear this plan and start a new one?")) {
      setSchedule(null);
      localStorage.removeItem('studyPulse_Plan');
    }
  };

  // Calculate Progress
  const completedCount = schedule ? schedule.filter(t => t.status === 'completed').length : 0;
  const progress = schedule ? (completedCount / schedule.length) * 100 : 0;

  return (
    <div style={{ maxWidth: '800px', margin: '40px auto', padding: '20px', fontFamily: 'Arial' }}>
      
      {/* 1. IF NO SCHEDULE: Show the Plan Generator Form */}
      {!schedule ? (
        <div style={{ background: 'white', padding: '30px', borderRadius: '10px', boxShadow: '0 4px 10px rgba(0,0,0,0.1)' }}>
          <h1 style={{ color: '#2c3e50' }}>Create Your Study Plan</h1>
          
          <div style={{ marginBottom: '20px' }}>
            <label style={{ display: 'block', marginBottom: '8px', fontWeight: 'bold' }}>Target Exam Date:</label>
            <input 
              type="date" 
              value={targetDate} 
              onChange={(e) => setTargetDate(e.target.value)} 
              style={{ width: '100%', padding: '12px', borderRadius: '5px', border: '1px solid #ddd' }} 
            />
          </div>

          <div style={{ marginBottom: '20px' }}>
            <label style={{ display: 'block', marginBottom: '8px', fontWeight: 'bold' }}>Syllabus (Topics separated by commas):</label>
            <textarea 
              placeholder="e.g. React Hooks, Node.js Middleware, MongoDB Aggregation" 
              value={syllabus} 
              onChange={(e) => setSyllabus(e.target.value)} 
              style={{ width: '100%', height: '120px', padding: '12px', borderRadius: '5px', border: '1px solid #ddd' }} 
            />
          </div>

          <button 
            onClick={generateSchedule} 
            disabled={loading}
            style={{ width: '100%', padding: '15px', background: '#3498db', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer', fontSize: '1rem', fontWeight: 'bold' }}
          >
            {loading ? 'Generating AI Plan...' : 'Generate Study Schedule'}
          </button>
        </div>
      ) : (
        /* 2. IF SCHEDULE EXISTS: Show the Roadmap & Progress */
        <>
          <h1 style={{ color: '#2c3e50' }}>My Roadmap</h1>
          
          {/* Progress Bar */}
          <div style={{ width: '100%', height: '20px', background: '#eee', borderRadius: '10px', marginBottom: '10px', overflow: 'hidden' }}>
            <div style={{ width: `${progress}%`, background: '#27ae60', height: '100%', transition: 'width 0.5s ease' }} />
          </div>
          <p style={{ textAlign: 'right', fontWeight: 'bold' }}>{Math.round(progress)}% Completed</p>

          {/* Day Grid */}
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '20px', marginTop: '20px' }}>
            {schedule.map((item) => (
              <div 
                key={item.day}
                onClick={() => item.status !== 'completed' && navigate(`/study-session/${item.day}`)}
                style={{ 
                  padding: '20px', 
                  border: '1px solid #ddd', 
                  borderRadius: '10px', 
                  background: item.status === 'completed' ? '#d4edda' : '#fff',
                  cursor: item.status === 'completed' ? 'default' : 'pointer'
                }}
              >
                <strong>Day {item.day}</strong>
                <p>{item.topic}</p>
                <span style={{ color: item.status === 'completed' ? 'green' : '#e67e22', fontWeight: 'bold' }}>
                  {item.status === 'completed' ? '✅ Completed' : '⏳ Start'}
                </span>
              </div>
            ))}
          </div>

          {/* Reset Button (Only at 100% or via manual reset) */}
          <button 
            onClick={handleResetPlan}
            style={{ marginTop: '40px', color: '#e74c3c', background: 'none', border: 'none', cursor: 'pointer', textDecoration: 'underline' }}
          >
            Clear and Start New Plan
          </button>
        </>
      )}
    </div>
  );
};

export default Dashboard;
